export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "11:45。資料室附近的家庭餐廳。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪坐在靠窗的位子。點了一杯水。沒有點餐。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把筆記本翻開。放在桌上。手機放在旁邊。螢幕朝下。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯先跳過私人筆記。只抄文件。A 和 B。只寫紙上有的。不混進我記得的。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻到一頁空白頁。開始寫。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "文件 A——事前運用變更申請。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "設定檔：TOKYO。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "預定測試窗：星期一 20:55–21:35。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "原映射：標準運用群（公開版遮蔽）。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "臨時映射：測試群 G07。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "預定處置：測試結束後回復標準運用群。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "提出方：TKS 運用部門。核准方：灣岸新交通運用主管。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "文件 B——多通道測試參數附頁。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車站廣播：0ms。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "月台／車內顯示：+1200ms。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "官方「灣岸防災」應用推送：+7000ms。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "備援簡訊：+9500ms。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "製作方：TKS 技術部。確認方：灣岸新交通測試負責人。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "同一變更申請編號。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她抄完。看著這兩份。然後在旁邊畫了一條直線。把頁面分成左右兩半。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "左邊寫——文件可證明。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "右邊寫——只有澪記得／觀察過。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯分開。左邊：文件能證的。右邊：只有我記的。不混。右邊不能假裝有左邊撐腰。左邊也不能自動解釋右邊。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在左邊寫。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "星期一預定將 TOKYO 暫接 G07。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機推送預定 +7000ms。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "參數屬多通道順序測試。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "測試後預定回復。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在右邊寫。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一輪——公共廣播早於手機通知。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二輪——手數約六至八秒。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白光前公共螢幕與手機也有先後感。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不知道白光時是否仍使用同一設定。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯左邊四行。右邊四行。左邊有文件。右邊只有我。左邊是計畫。右邊是觀察。它們吻合——但吻合不是證明。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在右邊第二行旁邊加了一行小字。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "無獨立時基，不可當證據。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯六到八秒。手數的。沒計時器。沒錄影。沒獨立時基。同一支手機不能既測又計時。當時在阻止攻擊。不可能停下來測。所以這個數字——只是感覺。不算證據。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她放下筆。拿起手機。翻轉過來。解鎖。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但有一樣東西可以查。第二輪手機裡還留著星期一的通知紀錄。通知來源。通知內容。這些是手機系統自動記錄的。不是我的記憶。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她打開通知紀錄。翻到星期一。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "通知紀錄還在。系統保留的。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "來源——灣岸防災。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "通知內容——與公共廣播相同的災害警報測試訊息。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "時間——系統記錄的通知接收時間。但——", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯沒有精確的亮起時間。系統記的是接收時間。不是我看見的時間。中間還有處理延遲。所以——來源是灣岸防災。內容和廣播一樣。但手機是不是七秒整亮起——不能確認。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在筆記本左邊那一半的底部加了一行。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二輪通知來源＝灣岸防災應用＝文件 B 所列通道。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯同一條通道。文件 B 規定灣岸防災 +7000ms。我第二輪通知來源也是灣岸防災。所以——文件和觀察至少在同一條服務上。不是不同系統。不是巧合。同一個應用。同一條通道。但——同一條通道不等於同一台裝置的結果。伺服器晚七秒送。手機何時亮——看網路和裝置。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著筆記本上那條分隔線。左邊。右邊。涇渭分明。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她打開另一個畫面。通訊軟體。找到佐伯的對話。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯傳給佐伯。只傳裁切過的公開文件。不提警方。不提小鏡子。不提 G07 孩子。只讓他看 A 和 B 的公開部分。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從手機相簿裡選了幾張照片。附件三的變更申請頁——裁掉個人閱覽申請資訊。附件四的參數表——只保留通道和補正值。申請編號——保留。配布日期——保留。委員會章——保留。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把裁切圖傳給佐伯。附了一行字。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "今天在資料室找到的。事前文件。只看公開部分。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "等。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:05。佐伯回覆了。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "文件 A 和 B 都是事前？", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "還缺執行結果。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯佐伯。第一句就指出缺什麼。事前文件。缺事後。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "對。還沒找到事後復舊確認。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "G07 可能只是設備測試群。不同專案可能有各自的 G07。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在提醒我。研究資料裡的 G07 和警報系統裡的 G07 可能只是普通重號。兩個不同部署各自編了第七群。不能因為號碼一樣就當成同一批對象。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "+7000ms 可能只是通道順序。文件證明七秒後才發送，不證明妳手機七秒整顯示。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "沒有端點表，就不知道 G07 裡是什麼。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯每一句都在踩煞車。他用最簡單的話把我的興奮壓回去。不是不想相信。是怕我也被錯誤的希望騙。他見過太多家屬把「像」當成「是」。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著佐伯的訊息。沒有反駁。因為他說的全部成立。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "現在只知道，他們打算把名叫東京的設定接到第七群，讓伺服器在廣播七秒後才送出手機通知。還不知道第七群裡放的是什麼，也不知道每台手機實際幾秒後看見。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這是佐伯的翻譯。把參數表和變更申請壓成一句普通人能聽懂的話。沒有推測。沒有跳步。只有文件已經寫的。和文件還沒寫的。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她回覆。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "我還缺一份事後文件。確認配置確實啟用並回復。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "下午再查。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "文件 A 只證明計畫。不要當成已經執行。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "收到。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機放下。看著筆記本。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "左邊。右邊。分隔線。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯佐伯說得對。兩份表還不是答案。A 證明計畫。B 證明參數。都是事前。都不是事後。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我還需要一份東西。星期一之後形成的。值班主管製作的。引用 A 的申請編號和 B 的附頁版本。運用結果確認。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在筆記本底部畫了一個箭頭。從「事前」指向「事後」。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯那份東西才能把計畫變成執行。才能證明 TOKYO 確實接上 G07。才能證明 +7000ms 確實被啟用。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在筆記本底部寫——", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下一步：事後運用結果／復舊確認摘要。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在旁邊加了一行。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "趕在資料室關閉前。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:20。她終於點了一杯咖啡。服務生送來的時候，她看著窗外。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十二點二十分的太陽。距星期一 06:13——大約還有兩天十七個小時。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真失蹤第十一天。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯兩份事前文件。七秒。G07。TOKYO。吻合我記得的。但吻合不是因果。計畫不是執行。同一條通道不是同一台裝置的結果。需要第三份文件。需要紙本。需要在資料室關門之前找到。", background: Background.Chapter_14_Ch14_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她喝了一口咖啡。燙的。她沒有等它涼。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "筆記本上那條分隔線還在。左邊是文件。右邊是她。中間的線不會消失。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但左邊那一欄，今天多了兩行。一行寫著 TOKYO 接到 G07。一行寫著 +7000ms。", background: Background.Chapter_14_Ch14_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "紙上的數字不會因為她離開資料室而改變。它印在那裡。在她看見之前就已經印在那裡。", background: Background.Chapter_14_Ch14_Act3_S0 },
];
